    orig_AppCacheGetIEGroupList = GetProcAddress(hOriginal, "AppCacheGetIEGroupList");
    orig_AppCacheGetInfo = GetProcAddress(hOriginal, "AppCacheGetInfo");
    orig_AppCacheGetManifestUrl = GetProcAddress(hOriginal, "AppCacheGetManifestUrl");
    orig_AppCacheLookup = GetProcAddress(hOriginal, "AppCacheLookup");
    orig_CommitUrlCacheEntryA = GetProcAddress(hOriginal, "CommitUrlCacheEntryA");
    orig_CommitUrlCacheEntryBinaryBlob = GetProcAddress(hOriginal, "CommitUrlCacheEntryBinaryBlob");
    orig_CommitUrlCacheEntryW = GetProcAddress(hOriginal, "CommitUrlCacheEntryW");
    orig_CreateMD5SSOHash = GetProcAddress(hOriginal, "CreateMD5SSOHash");
